<script>
    (function() {
 const root = document.getElementById('limite-x1-fragmento');
 const $ = sel => root.querySelector(sel);
 const $$ = sel => Array.from(root.querySelectorAll(sel));

 // Helper MathJax v3
 function renderMath(node) {
   if (!window.MathJax) return;
   const target = node || root;
   const doTypeset = () => {
if (typeof MathJax.typesetPromise === 'function') {
  MathJax.typesetPromise([target]).catch(() => {});
} else if (typeof MathJax.typeset === 'function') {
  try { MathJax.typeset([target]); } catch (_) {}
}
   };
   if (MathJax.startup && MathJax.startup.promise) {
MathJax.startup.promise.then(doTypeset);
   } else {
// Por si el script aún no terminó de inicializar
setTimeout(doTypeset, 0);
   }
 }

 function parseNum(v) {
   if (typeof v !== 'string') return NaN;
   const s = v.replace(',', '.').trim();
   if (!s) return NaN;
   return Number(s);
 }

 // f(x) = (x^3 - 1) / (x - 1) = x^2 + x + 1  (para x ≠ 1)
 function f(x) { return (x*x + x + 1); }

 function near(a, b, tol = 1e-2) {
   return isFinite(a) && isFinite(b) && Math.abs(a - b) <= tol;
 }

 function check() {
   let correctCount = 0;
   $$('.lx1-in').forEach(cell => {
const x = parseNum(cell.getAttribute('data-x'));
const expected = f(x);
const user = parseNum(cell.value);
const ok = near(user, expected);
const okEl = cell.parentElement.querySelector('.lx1-ok');
const badEl = cell.parentElement.querySelector('.lx1-bad');
okEl.style.display = ok ? '' : 'none';
badEl.style.display = ok ? 'none' : '';
if (ok) correctCount++;
   });

   const expectedLimit = 3; // f(1) sería 1+1+1
   const l = parseNum($('#lx1-lim-left').value);
   const r = parseNum($('#lx1-lim-right').value);
   const all = parseNum($('#lx1-lim-all').value);

   const mark = (idOK, idBAD, cond) => {
$(idOK).style.display = cond ? '' : 'none';
$(idBAD).style.display = cond ? 'none' : '';
   };
   mark('#lx1-left-mark', '#lx1-left-mark-bad', near(l, expectedLimit));
   mark('#lx1-right-mark', '#lx1-right-mark-bad', near(r, expectedLimit));
   mark('#lx1-all-mark', '#lx1-all-mark-bad', near(all, expectedLimit));

   const done =
correctCount === $$('.lx1-in').length &&
near(l, expectedLimit) && near(r, expectedLimit) && near(all, expectedLimit);

   const fb = $('#lx1-feedback');
   fb.style.display = '';
   fb.innerHTML = done
? "🔵 ¡Bien! Al acercarnos a \(x=1\) por ambos lados, los valores se aproximan a \(3\). Por tanto, \(\\displaystyle \\lim_{x\	o 1} f(x)=3\)."
: "🟡 Revisa tus cálculos. Recuerda que para \(x\
eq 1\), la fracción se simplifica a \(x^{2}+x+1\).";

   renderMath(fb);
 }

 function clearAll() {
   $$('.lx1-in').forEach(cell => {
cell.value = '';
cell.parentElement.querySelector('.lx1-ok').style.display = 'none';
cell.parentElement.querySelector('.lx1-bad').style.display = 'none';
   });
   ['#lx1-lim-left','#lx1-lim-right','#lx1-lim-all'].forEach(id => { $(id).value = ''; });
   ['#lx1-left-mark','#lx1-right-mark','#lx1-all-mark','#lx1-left-mark-bad','#lx1-right-mark-bad','#lx1-all-mark-bad']
.forEach(id => { $(id).style.display = 'none'; });
   const fb = $('#lx1-feedback'); fb.style.display = 'none'; fb.innerHTML = '';
 }

 function showHint() {
   const fb = $('#lx1-feedback');
   fb.style.display = '';
   fb.innerHTML = "💡 Pista: factoriza \(x^{3}-1=(x-1)(x^{2}+x+1)\). Para \(x\
e 1\), \(\\dfrac{x^{3}-1}{x-1}=x^{2}+x+1\). Evalúa en cada \(x\) de la tabla.";
   renderMath(fb);
 }

 $('#lx1-btn-check').addEventListener('click', check);
 $('#lx1-btn-clear').addEventListener('click', clearAll);
 $('#lx1-btn-pista').addEventListener('click', showHint);

 // Tipografiar el bloque inicial
 renderMath(root);
    })();
  </script>
</div></div>"}

