<script>
    (function() {
 const root = document.getElementById('limite-piecewise-fragmento');
 const $ = sel => root.querySelector(sel);
 const $$ = sel => Array.from(root.querySelectorAll(sel));

 // Parseo flexible: admite coma decimal
 function parseNum(v) {
   if (typeof v !== 'string') return NaN;
   const s = v.replace(',', '.').trim();
   if (!s) return NaN;
   return Number(s);
 }

 // g(x) por trozos: 2x+1 si x<1 ; x^2 si x>1 (no definida en x=1)
 function g(x) {
   if (x < 1) return 2*x + 1;
   if (x > 1) return x*x;
   return NaN;
 }

 function near(a, b, tol = 1e-2) {
   return isFinite(a) && isFinite(b) && Math.abs(a - b) <= tol;
 }

 // Aceptamos varias formas de escribir "no existe"
 function isNoLimit(text) {
   if (typeof text !== 'string') return false;
   const s = text.toLowerCase().normalize('NFD').replace(/\p{Diacritic}/gu,'').trim();
   return (
s === 'no existe' || s === 'no-existe' || s === 'no hay limite' ||
s === 'no hay' || s === 'dne' || s === 'n.e.' || s === 'ne' ||
s === 'no' || s === '∄' || s.includes('no existe') || s.includes('no hay limite') ||
s.includes('no hay limite') || s.includes('no hay') || s.includes('no limite')
   );
 }

 function check() {
   let correctCount = 0;
   // Celdas de tablas
   $$('.pw1-in').forEach(cell => {
const x = parseNum(cell.getAttribute('data-x'));
const expected = g(x);
const user = parseNum(cell.value);
const ok = near(user, expected);
const okEl = cell.parentElement.querySelector('.pw1-ok');
const badEl = cell.parentElement.querySelector('.pw1-bad');
okEl.style.display = ok ? '' : 'none';
badEl.style.display = ok ? 'none' : '';
if (ok) correctCount++;
   });

   // Límites laterales esperados
   const L = 3; // lim x->1^- (2x+1) = 3
   const R = 1; // lim x->1^+ (x^2) = 1

   const l = parseNum($('#pw1-lim-left').value);
   const r = parseNum($('#pw1-lim-right').value);
   const all = $('#pw1-lim-all').value;

   const mark = (okId, badId, cond) => {
$(okId).style.display = cond ? '' : 'none';
$(badId).style.display = cond ? 'none' : '';
   };
   mark('#pw1-left-mark', '#pw1-left-mark-bad', near(l, L));
   mark('#pw1-right-mark', '#pw1-right-mark-bad', near(r, R));

   // Para el límite total aceptamos respuestas tipo "no existe"
   const allOK = isNoLimit(all) || all === '' ? false : false; // placeholder para consistencia
   // Mostramos ✅ si escribió una forma válida de "no existe"
   const totalIsDNE = isNoLimit(all);
   mark('#pw1-all-mark', '#pw1-all-mark-bad', totalIsDNE);

   const done =
correctCount === $$('.pw1-in').length &&
near(l, L) && near(r, R) && totalIsDNE;

   const fb = $('#pw1-feedback');
   fb.style.display = '';
   fb.innerHTML = done
? "🔵 ¡Bien! Se obtiene \(\\lim_{x\	o 1^{-}} g(x)=3\) y \(\\lim_{x\	o 1^{+}} g(x)=1\). Como no coinciden, \(\\lim_{x\	o 1} g(x)\) <b>no existe</b>."
: "🟡 Revisa tus cálculos. Recuerda que para \(x<1\), \(g(x)=2x+1\); y para \(x>1\), \(g(x)=x^{2}\). Los límites laterales en \(x=1\) deben salir \(3\) y \(1\).";

   if (window.MathJax && window.MathJax.typeset) window.MathJax.typeset([fb, root]);
 }

 function clearAll() {
   $$('.pw1-in').forEach(cell => {
cell.value = '';
cell.parentElement.querySelector('.pw1-ok').style.display = 'none';
cell.parentElement.querySelector('.pw1-bad').style.display = 'none';
   });
   ['#pw1-lim-left','#pw1-lim-right','#pw1-lim-all'].forEach(id => { $(id).value = ''; });
   ['#pw1-left-mark','#pw1-right-mark','#pw1-all-mark','#pw1-left-mark-bad','#pw1-right-mark-bad','#pw1-all-mark-bad']
.forEach(id => { $(id).style.display = 'none'; });
   const fb = $('#pw1-feedback'); fb.style.display = 'none'; fb.innerHTML = '';
 }

 function showHint() {
   const fb = $('#pw1-feedback');
   fb.style.display = '';
   fb.innerHTML =
"💡 Pista: Para \(x<1\), usa \(g(x)=2x+1\) (deberías acercarte a \(3\)). Para \(x>1\), usa \(g(x)=x^2\) (deberías acercarte a \(1\)). "+
"Si los límites laterales no coinciden, el límite en \(x=1\) <i>no existe</i>.";
   if (window.MathJax && window.MathJax.typeset) window.MathJax.typeset([fb]);
 }

 $('#pw1-btn-check').addEventListener('click', check);
 $('#pw1-btn-clear').addEventListener('click', clearAll);
 $('#pw1-btn-pista').addEventListener('click', showHint);
    })();
