MathJax.startup.promise.then(doTypeset);
   } else {
setTimeout(doTypeset, 0);
   }
 }

 // Parseo flexible (coma o punto)
 function parseNum(v) {
   if (typeof v !== 'string') return NaN;
   const s = v.replace(',', '.').trim();
   if (!s) return NaN;
   return Number(s);
 }

 // Tolerancia relativa y absoluta para números grandes/pequeños
 function nearRel(a, b, tolRel = 0.02, tolAbs = 1e-2) {
   if (!isFinite(a) || !isFinite(b)) return false;
   return Math.abs(a - b) <= Math.max(tolAbs, tolRel * Math.abs(b));
 }

 // f(x) = 1/(x-4), x ≠ 4
 function f(x) { return 1 / (x - 4); }

 // Reconocer entradas de infinito en texto para límites
 function isNegInf(t) {
   if (typeof t !== 'string') return false;
   const s = t.trim().toLowerCase();
   return s === '-inf' || s === '-infty' || s === '-∞' || s === '−∞' || s === 'menos infinito' || s === 'menos-infinito';
 }
 function isPosInf(t) {
   if (typeof t !== 'string') return false;
   const s = t.trim().toLowerCase();
   return s === '+inf' || s === 'inf' || s === '+infty' || s === 'infty' || s === '+∞' || s === '∞' || s === 'mas infinito' || s === 'más infinito' || s === 'mas-infinito' || s === 'más-infinito' || s === 'infinito';
 }
 function isNoLimit(t) {
   if (typeof t !== 'string') return false;
   const s = t.trim().toLowerCase().normalize('NFD').replace(/\p{Diacritic}/gu,'');
   return s === 'no existe' || s === 'no hay limite' || s === 'dne' || s === 'ne' || s.includes('no existe') || s.includes('no hay limite') || s.includes('diverge') || s.includes('diverge') || s.includes('diverge');
 }

 function check() {
   // 1) Celdas de las tablas
   let okCount = 0;
   $$('.av-in').forEach(cell => {
const x = parseNum(cell.getAttribute('data-x'));
const expected = f(x);
const user = parseNum(cell.value);
const ok = nearRel(user, expected);
const okEl = cell.parentElement.querySelector('.av-ok');
const badEl = cell.parentElement.querySelector('.av-bad');
okEl.style.display = ok ? '' : 'none';
badEl.style.display = ok ? 'none' : '';
if (ok) okCount++;
   });

   // 2) Límites laterales
   const leftAns = $('#av-lim-left').value;
   const rightAns = $('#av-lim-right').value;
   const allAns = $('#av-lim-all').value;

   const leftOK = isNegInf(leftAns);
   const rightOK = isPosInf(rightAns);
   const totalOK = isNoLimit(allAns);

   const mark = (okId, badId, cond) => {
$(okId).style.display = cond ? '' : 'none';
$(badId).style.display = cond ? 'none' : '';
   };
   mark('#av-left-mark', '#av-left-mark-bad', leftOK);
   mark('#av-right-mark', '#av-right-mark-bad', rightOK);
   mark('#av-all-mark', '#av-all-mark-bad', totalOK);

   // 3) Feedback
   const fb = $('#av-feedback');
   fb.style.display = '';
   if (
okCount === $$('.av-in').length &&
leftOK && rightOK && totalOK
   ) {
fb.innerHTML = "🔵 ¡Bien! Se cumple que \(\\displaystyle \\lim_{x\	o 4^{-}} \	frac{1}{x-4}=-\\infty\) y \(\\displaystyle \\lim_{x\	o 4^{+}} \	frac{1}{x-4}=+\\infty\). Al no coincidir (y ser infinitos opuestos), \(\\lim_{x\	o 4} f(x)\) <b>no existe</b>.";
   } else {
fb.innerHTML = "🟡 Revisa. Recuerda: si \(x<4\) entonces \(x-4<0\\Rightarrow f(x)<0\) y crece en magnitud hacia \(-\\infty\); si \(x>4\), \(f(x)>0\) y crece hacia \(+\\infty\).";
   }
   renderMath(fb);
 }

 function clearAll() {
   $$('.av-in').forEach(cell => {
cell.value = '';
cell.parentElement.querySelector('.av-ok').style.display = 'none';
cell.parentElement.querySelector('.av-bad').style.display = 'none';
   });
   ['#av-lim-left','#av-lim-right','#av-lim-all'].forEach(id => { $(id).value = ''; });
   ['#av-left-mark','#av-right-mark','#av-all-mark','#av-left-mark-bad','#av-right-mark-bad','#av-all-mark-bad']
.forEach(id => { $(id).style.display = 'none'; });
   const fb = $('#av-feedback'); fb.style.display = 'none'; fb.innerHTML = '';
 }

 function showHint() {
   const fb = $('#av-feedback');
   fb.style.display = '';
   fb.innerHTML =
"💡 Pista: \(f(x)=\\dfrac{1}{x-4}\). Para \(x=3.9,3.99,3.999\), el denominador es negativo y pequeño ⇒ \(f(x)\) es negativo y grande en magnitud: se acerca a \(-\\infty\).<br/>" +
"Para \(x=4.1,4.01,4.001\), el denominador es positivo y pequeño ⇒ \(f(x)\	o +\\infty\).";
   renderMath(fb);
 }

 // Eventos
 $('#av-btn-check').addEventListener('click', check);
 $('#av-btn-clear').addEventListener('click', clearAll);
 $('#av-btn-pista').addEventListener('click', showHint);

 // Tipografiar el bloque inicial
 renderMath(root);
    })();
  </script>
