MathJax.startup.promise.then(doTypeset);
   } else setTimeout(doTypeset, 0);
 }

 // Función cos(1/x)
 function f(x) { return Math.cos(1/x); }

 function parseNum(v) {
   if (typeof v !== 'string') return NaN;
   return Number(v.replace(',', '.').trim());
 }

 function near(a, b, tol = 1e-2) {
   return isFinite(a) && isFinite(b) && Math.abs(a - b) < tol;
 }

 function check() {
   let okCount = 0;
   $$('.cos-in').forEach(cell => {
const x = parseNum(cell.getAttribute('data-x'));
const expected = f(x);
const user = parseNum(cell.value);
const ok = near(user, expected, 1e-1);
cell.parentElement.querySelector('.cos-ok').style.display = ok ? '' : 'none';
cell.parentElement.querySelector('.cos-bad').style.display = ok ? 'none' : '';
if (ok) okCount++;
   });

   const ans = $('#cos-lim-all').value.toLowerCase().trim();
   const noLimit = ans.includes("no existe") || ans.includes("osc") || ans.includes("dne");
   $('#cos-all-mark').style.display = noLimit ? '' : 'none';
   $('#cos-all-mark-bad').style.display = noLimit ? 'none' : '';

