 }

 function clearAll() {
   $$('.cos-in').forEach(cell => {
cell.value = '';
cell.parentElement.querySelector('.cos-ok').style.display = 'none';
cell.parentElement.querySelector('.cos-bad').style.display = 'none';
   });
   $('#cos-lim-all').value = '';
   $('#cos-all-mark').style.display = 'none';
   $('#cos-all-mark-bad').style.display = 'none';
   $('#cos-feedback').style.display = 'none';
 }

 function showHint() {
   const fb = $('#cos-feedback');
   fb.style.display = '';
   fb.innerHTML = "💡 Pista: al acercarte a 0, el argumento \\(1/x\\) crece sin límite. El coseno oscila siempre entre -1 y 1, sin estabilizarse en ningún valor.";
   renderMath(fb);
 }

 $('#cos-btn-check').addEventListener('click', check);
 $('#cos-btn-clear').addEventListener('click', clearAll);
 $('#cos-btn-pista').addEventListener('click', showHint);

 renderMath(root);
    })();
  </script>
</div></div>"}

{"textTextarea":"<p>
<script type="text/javascript"> 
  $(window).load(function(){
    $.each([1,2,3,4,5], function(index , value ) {
 $("p.toggle-idevice a").eq(value).click();
    })
  });
</script>
</p>
<div id="mx-limites-1" style="box-sizing: border-box; border: 3px solid #e11; border-radius: 6px; padding: 16px 18px; background: #f5f9f6; font-family: system-ui,-apple-system,Segoe UI,Roboto,Ubuntu,Cantarell,'Helvetica Neue',Arial,'Noto Sans',sans-serif; color: #0b0b0b; line-height: 1.55; max-width: 900px; margin: 0;">
<div style="font-weight: 800; font-size: 20px; margin-bottom: 10px;">Límite y límites laterales</div>
<p style="margin: 0 0 10px 0;">Dada una función \(f(x)\) y un punto \(x=a\), se dice que el límite de \(f(x)\), cuando \(x\) se aproxima a \(a\) es \(L\) si se verifica que:</p>
<ol style="margin: 0 0 10px 22px; padding: 0;">
<li style="margin: 6px 0;">Existen \(\displaystyle \lim_{x	o a^{+}} f(x)\) y \(\displaystyle \lim_{x	o a^{-}} f(x)\).</li>
<li style="margin: 6px 0;">Son iguales: \(\displaystyle \lim_{x	o a^{+}} f(x)=\lim_{x	o a^{-}} f(x)=L\).</li>
</ol>
<p style="margin: 10px 0 0 0;">Entonces decimos que:</p>
<p style="margin: 8px 0 0 0; font-size: 17px; font-weight: 600; text-align: center;">\[ \lim_{x	o a} f(x) \;=\; \lim_{x	o a^{+}} f(x) \;=\; \lim_{x	o a^{-}} f(x) \;=\; L. \]</p>
</div>
<!-- Encapsulación JS opcional: no afecta fuera del contenedor -->
<p>
<script>
(function(){
  const box = document.getElementById('mx-limites-1');
  if(!box) return;
  // Evita que estilos externos colapsen márgenes internos
  box.querySelectorAll('p,ol,li').forEach(function(el){
    el.style.marginBlockStart = el.style.marginBlockStart || '';
    el.style.marginBlockEnd   = el.style.marginBlockEnd   || '';
  });
})();
</script>
</p>"}

{"textTextarea":"<!-- FRAGMENTO AUTÓNOMO: Continuidad de una función en un punto (con LaTeX/MathJax) -->
<div id="mx-continuidad-1" style="box-sizing: border-box; border: 3px solid #e11; border-radius: 6px; padding: 16px 18px; background: #fefefe; font-family: system-ui,-apple-system,Segoe UI,Roboto,Ubuntu,Cantarell,'Helvetica Neue',Arial,'Noto Sans',sans-serif; color: #0b0b0b; line-height: 1.55; max-width: 900px; margin: 0;">
<div style="font-weight: 800; font-size: 20px; margin-bottom: 10px;">Continuidad de una función en un punto</div>
<p style="margin: 0 0 10px 0;">Sea una función \(f(x)\) y un punto \(x=a\). Decimos que \(f\) es <strong>continua</strong> en \(x=a\) si se cumplen simultáneamente las siguientes condiciones:</p>
<ol style="margin: 0 0 10px 22px; padding: 0;">
<li style="margin: 6px 0;">Existe \(f(a)\).</li>
<li style="margin: 6px 0;">Existe \(\displaystyle \lim_{x	o a} f(x)\).</li>
<li style="margin: 6px 0;">Se cumple que \(\displaystyle \lim_{x	o a} f(x) = f(a)\).</li>
</ol>
<p style="margin: 10px 0 0 0;">Simbólicamente:</p>
<p style="margin: 8px 0 0 0; font-size: 17px; font-weight: 600; text-align: center;">\[ \lim_{x	o a} f(x) = f(a). \]</p>
</div>
<!-- Encapsulación JS opcional -->
<p>
<script>
(function(){
  const box = document.getElementById('mx-continuidad-1');
  if(!box) return;
  box.querySelectorAll('p,ol,li').forEach(function(el){
    el.style.marginBlockStart = el.style.marginBlockStart || '';
    el.style.marginBlockEnd   = el.style.marginBlockEnd   || '';
  });
})();
</script>
</p>
<p>Visualmente, podemos estar en alguno de estos casos:<br /><img src="{{context_path}}/content/resources/img0.8.png" width="790" height="187" alt="Cuatro casos de límites" /></p>
<p>¿Para cuales de los cuatro casos anteriores crees que se dice que existe límite? ¿En qué casos se dice que la función es contínua?</p>"}

{"textTextarea":"<p>
<script type="text/javascript"> 
