{"textInfoDurationTextInput":"","textInfoDurationInput":"","textInfoParticipantsTextInput":"","textInfoParticipantsInput":"","textFeedbackInput":"","textFeedbackTextarea":"","textTextarea":"<div class="exe-text-activity"><p>
<script type="text/javascript"> 
